from zeep import Client
from zeep.transports import Transport
from requests import Session
from lxml import etree

def create_soap_client(wsdl_url):
    session = Session()
    transport = Transport(session=session)
    client = Client(wsdl_url, transport=transport)
    return client

def lookup_policy_direct_xml(wsdl_url, policy_number, customer_name):
    soap_body = f"""<?xml version="1.0" encoding="UTF-8"?>
    <soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" 
                      xmlns:ins="http://insurance.service.com/">
        <soapenv:Header/>
        <soapenv:Body>
            <ins:PolicyLookup>
                <ins:PolicyNumber>{policy_number}</ins:PolicyNumber>
                <ins:CustomerName>{customer_name}</ins:CustomerName>
            </ins:PolicyLookup>
        </soapenv:Body>
    </soapenv:Envelope>"""
    
    return soap_body

def send_soap_request(service_url, soap_body):
    session = Session()
    headers = {
        'Content-Type': 'text/xml; charset=utf-8',
        'SOAPAction': 'PolicyLookup'
    }
    response = session.post(service_url, data=soap_body, headers=headers)
    return response.text

def lookup_policy_zeep(wsdl_url, policy_number, customer_name):
    client = create_soap_client(wsdl_url)
    
    soap_xml = f"""
    <PolicyLookup xmlns="http://insurance.service.com/">
        <PolicyNumber>{policy_number}</PolicyNumber>
        <CustomerName>{customer_name}</CustomerName>
    </PolicyLookup>"""
    
    root = etree.fromstring(soap_xml)
    
    response = client.service.PolicyLookup(root)
    return response

def get_policy_quote(wsdl_url, policy_number, customer_name, date_of_birth=None, address=None):
    soap_envelope = f"""<?xml version="1.0" encoding="UTF-8"?>
    <soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" 
                      xmlns:ins="http://insurance.service.com/">
        <soapenv:Header/>
        <soapenv:Body>
            <ins:GetQuote>
                <ins:PolicyNumber>{policy_number}</ins:PolicyNumber>
                <ins:CustomerName>{customer_name}</ins:CustomerName>"""
    
    if date_of_birth:
        soap_envelope += f"""
                <ins:DateOfBirth>{date_of_birth}</ins:DateOfBirth>"""
    
    if address:
        soap_envelope += f"""
                <ins:Address>{address}</ins:Address>"""
    
    soap_envelope += """
            </ins:GetQuote>
        </soapenv:Body>
    </soapenv:Envelope>"""
    
    return soap_envelope

def search_policies(wsdl_url, search_criteria):
    criteria_xml = ""
    for key, value in search_criteria.items():
        criteria_xml += f"<ins:{key}>{value}</ins:{key}>"
    
    soap_body = f"""<?xml version="1.0" encoding="UTF-8"?>
    <soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" 
                      xmlns:ins="http://insurance.service.com/">
        <soapenv:Header/>
        <soapenv:Body>
            <ins:SearchPolicies>
                {criteria_xml}
            </ins:SearchPolicies>
        </soapenv:Body>
    </soapenv:Envelope>"""
    
    return soap_body

def update_policy_details(wsdl_url, policy_number, updates):
    update_fields = ""
    for field, value in updates.items():
        update_fields += f"<ins:{field}>{value}</ins:{field}>"
    
    soap_message = f"""<?xml version="1.0" encoding="UTF-8"?>
    <soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" 
                      xmlns:ins="http://insurance.service.com/">
        <soapenv:Header/>
        <soapenv:Body>
            <ins:UpdatePolicy>
                <ins:PolicyNumber>{policy_number}</ins:PolicyNumber>
                {update_fields}
            </ins:UpdatePolicy>
        </soapenv:Body>
    </soapenv:Envelope>"""
    
    return soap_message

